using namespace std;

bool overlaps(vector<int> &a, vector<int> &b)
{
    return a[0] <= b[1] && b[0] <= a[1];
}

vector<vector<int>> merge(vector<vector<int>> &intervals)
{
    vector<vector<int>> result = intervals;

    bool merged = true;
    while (merged)
    {
        merged = false;
        for (int i = 0; i < result.size() && !merged; i++)
        {
            for (int j = i + 1; j < result.size() && !merged; j++)
            {
                if (overlaps(result[i], result[j]))
                {
                    result[i][0] = min(result[i][0], result[j][0]);
                    result[i][1] = max(result[i][1], result[j][1]);
                    result.erase(result.begin() + j);
                    merged = true;
                }
            }
        }
    }

    return result;
}

int main()
{
    vector<vector<int>> intervals = {{1, 3}, {2, 6}, {8, 10}, {15, 18}};

    auto result = merge(intervals);
    for (auto &iv : result) cout << "[" << iv[0] << "," << iv[1] << "] ";

    return 0;
}

