string largestNumber(vector<int> &nums)
{
    vector<string> strs;
    for (int n : nums) strs.push_back(to_string(n));

    sort(strs.begin(), strs.end(), [](string &a, string &b) {
        return a + b > b + a;
    });

    if (strs[0] == "0") return "0"; // all zeros case

    string result = "";
    for (string &s : strs) result += s;

    return result;
}

